def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower(); v = v.strip()
        if k in ('pending', 'risk'):
            n = int(v) if v.lstrip('-').isdigit() else 0
            if k == 'pending':
                out['pending'] = max(0, min(99, n))
            else:
                out['risk'] = max(0, min(100, n))
    return out
